#include <stdio.h>
#include <stdlib.h>
#include <omp.h>

#define N 1024
#define INF 99999

void floydwarshall(int *dist, int n) {
  for (int k = 0; k < n; k++) {
    #pragma omp target teams distribute parallel for collapse(2) map(tofrom: dist[0:n*n])
    for (int i = 0; i < n; i++) {
      for (int j = 0; j < n; j++) {
        int ik = dist[i * n + k];
        int kj = dist[k * n + j];
        int ij = dist[i * n + j];
        if (ik + kj < ij) {
          dist[i * n + j] = ik + kj;
        }
      }
    }
  }
}

int main() {
  int *dist = (int *)malloc(N * N * sizeof(int));
  if (!dist) {
    fprintf(stderr, "Failed to allocate memory\n");
    return 1;
  }

  // Initialize the distance matrix
  for (int i = 0; i < N; i++) {
    for (int j = 0; j < N; j++) {
      if (i == j)
        dist[i * N + j] = 0;
      else
        dist[i * N + j] = INF;
    }
  }

  // Example edges (you can customize this)
  dist[0 * N + 1] = 3;
  dist[1 * N + 2] = 1;
  dist[2 * N + 3] = 7;
  dist[3 * N + 0] = 2;

  floydwarshall(dist, N);

  // Print a small part of the result matrix
  for (int i = 0; i < 10; i++) {
    for (int j = 0; j < 10; j++) {
      if (dist[i * N + j] == INF)
        printf("INF ");
      else
        printf("%3d ", dist[i * N + j]);
    }
    printf("\n");
  }

  free(dist);
  return 0;
}
